body.script:
//
    const bareServerData = {
        "servers": [
            "https://rhw.one",
            "https://phantomnetwork.cloud",
            "https://artclass.site",
            "https://shuttleproxy.com"
        ]
    };

    function populateDropdown() {
        const select = document.getElementById('bareServerSelect');
        bareServerData.servers.forEach((server) => {
            const option = document.createElement('option');
            option.value = server;
            option.textContent = server;
            select.appendChild(option);
        });
    }

    // Base64 Self-Containment Pipeline
    async function loadProxyService() {
        if (!('serviceWorker' in navigator)) return;

        try {
            const cdnWorkerUrl = 'https://cdn.jsdelivr.net/gh/zaka13alt/uvsvg@main/sw.js';
            console.log('Downloading remote proxy code...');

            const response = await fetch(cdnWorkerUrl);
            const scriptText = await response.text();

            // Convert raw Ultraviolet code into a safe Base64 string
            // btoa(unescape(encodeURIComponent(...))) handles special symbols cleanly
            const base64Script = btoa(unescape(encodeURIComponent(scriptText)));
            const dataUrl = `data:application/javascript;base64,${base64Script}`;

            // Safely preserve and bind native register context
            const nativeRegister = navigator.serviceWorker.register.bind(navigator.serviceWorker);

            // Force override registration mappings
            navigator.serviceWorker.register = async function(url, options) {
                console.log("Routing proxy worker through local Base64 string injector.");

                // Execute worker registration via native browser engine rules using Data URL strings
                return nativeRegister(dataUrl, { 
                    scope: options.scope || '/uv/service/' 
                });
            };

            console.log("System initialization completed smoothly.");

        } catch (err) {
            console.error("Critical fallback failure:", err);
        }
    }

    window.addEventListener('load', () => {
        populateDropdown();
        loadProxyService();
    });
//
